// =====================================================================
// BUILD PAYLOAD -- merge the article with the LLM translation (if any)
// and produce the final object POSTed to your API.
// Works for BOTH branches of "Needs Translation?": when translation was
// skipped, $json is the article itself and its already-filled fields
// are picked up the same way.
// Defensive by design: if the LLM output is missing or malformed, the
// article still goes out using sensible fallbacks -- every text field
// is guaranteed non-empty.
// =====================================================================
const cur = $('Resolve Image').item.json;
const cfg = $('Config').first().json;
const aiOut = $json;

const FIELD_TYPES = ['title', 'short_description', 'description'];
const KEYS = cfg.languages.flatMap(l => FIELD_TYPES.map(f => f + '_' + l));

// Start from what we already have; LLM output only fills/overrides
// fields it actually returned non-empty.
let t = {};
for (const k of KEYS) t[k] = cur[k] || '';

const looksLikePayload = (o) =>
  o && typeof o === 'object' && !Array.isArray(o) &&
  KEYS.filter((k) => k in o).length >= Math.min(2, KEYS.length);

// The OpenAI node nests its result deep in the response (e.g.
// output[0].content[0].text). Walk the whole response, parsing JSON
// strings, and grab the first object carrying our language fields.
// Depth-limited to avoid pathological inputs.
function findPayload(nodeVal, depth) {
  if (nodeVal == null || depth > 8) return null;
  if (typeof nodeVal === 'string') {
    const s = nodeVal.trim();
    if (s.startsWith('{')) { try { return findPayload(JSON.parse(s), depth + 1); } catch (e) { return null; } }
    return null;
  }
  if (typeof nodeVal !== 'object') return null;
  if (looksLikePayload(nodeVal)) return nodeVal;
  const children = Array.isArray(nodeVal) ? nodeVal : Object.values(nodeVal);
  for (const c of children) {
    const found = findPayload(c, depth + 1);
    if (found) return found;
  }
  return null;
}

const parsed = findPayload(aiOut, 0);
if (parsed) {
  for (const k of KEYS) {
    if (parsed[k] != null && typeof parsed[k] === 'string' && parsed[k].trim()) t[k] = parsed[k];
  }
}

// Many APIs require every text field to be NON-EMPTY. If a translation
// came back empty, fall back per language: own field -> same field in
// another configured language -> the original source text -> the title.
// Guarantees no empty required field is ever POSTed.
const pick = (...vals) => { for (const v of vals) { if (typeof v === 'string' && v.trim()) return v; } return ''; };
const cap = (s, max) => { const v = s || ''; return v.length > max ? v.slice(0, max - 1).trim() + '…' : v; };

const langFields = {};
for (const l of cfg.languages) {
  const others = (f) => cfg.languages.filter(x => x !== l).map(x => t[f + '_' + x]);
  const title = pick(t['title_' + l], ...others('title'), cur.source_title);
  const shortd = cap(pick(t['short_description_' + l], ...others('short_description'), cur.source_short_description, title), cfg.shortDescriptionMaxChars);
  const desc = pick(t['description_' + l], ...others('description'), cur.source_description, shortd, title);
  langFields['title_' + l] = title;
  langFields['short_description_' + l] = shortd;
  langFields['description_' + l] = desc;
}

// "payload" is exactly what POST Article sends to your API.
return { json: {
  id: cur.id,
  payload: Object.assign({
    category_id: Number(cur.category_id),
    source_url: cur.source_url || '',
    published_at: cur.published_at || new Date().toISOString(),
    image: pick(cur.image, cfg.placeholderImage),
    status: 2  // adjust to whatever "published/pending" status your API expects
  }, langFields)
}};

// =====================================================================
// MARK SEEN -- record the article in the dedupe store ONLY if the
// POST succeeded (2xx). Failed posts stay unmarked, so they are
// retried automatically on the next run.
// =====================================================================
const article = $('Build Payload').item.json;
const status = $json.statusCode || $json.status || 0;
const ok = status >= 200 && status < 300;

if (!ok) {
  console.log('POST failed for ' + article.id + ' status=' + status);
  return { json: { id: article.id, posted: false, status } };
}

const sd = $getWorkflowStaticData('global');
sd.seenIds = sd.seenIds || {};
sd.seenIds[article.id] = Date.now();
return { json: { id: article.id, posted: true, status } };
